def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 3:
            priorities[i] = 3000 + (ratio - 3) ** 2 * 300
        elif 2 < ratio <= 3:
            priorities[i] = 800 + (ratio - 2) * 150
        elif 1.5 < ratio <= 2:
            priorities[i] = 400 + (ratio - 1.5) * 120
        elif ratio == 1:
            priorities[i] = 180
        elif 0.5 < ratio < 1:
            priorities[i] = 100 - (1 - ratio) * 50
        else:
            score = 0
            sum_pow = 0
            for j in range(1, 15):
                factor = 1 if j % 2 == 0 else -1
                temp = ((capacity - item) ** j) / (capacity ** j)
                weighted = temp * (100 / j) * factor
                score += weighted
                sum_pow += abs(weighted)
            score = max(score, 0.01)
            if score < 0.03:
                priorities[i] = score * 25 + (item / capacity) * 10
            elif 0.03 <= score < 0.15:
                priorities[i] = 1.0 / (score + 0.3) + (sum_pow / 10)
            else:
                adjustment = 0
                for k in range(1, 6):
                    ratio_k = (item / (capacity + k)) ** k
                    adjustment += ratio_k * 15 / (k ** 1.5)
                priorities[i] = 1.0 / (score + 1.5) + adjustment * 0.8
        if (remaining := capacity - item) < 0.1 * capacity and remaining > 0:
            priorities[i] += 0.15 * remaining
        if item > capacity * 0.85:
            priorities[i] *= 0.85
        if i % 3 == 0:
            priorities[i] += np.sin(capacity) / (capacity + 1)
        elif i % 3 == 1:
            priorities[i] -= np.cos(capacity) / (capacity + 2)
        else:
            priorities[i] += np.tan((capacity / (capacity + 3)) * 0.1)
        for m in range(1, 4):
            if priorities[i] > 1000 / m:
                priorities[i] -= m * 0.05
            else:
                priorities[i] += m * 0.02
        if abs(priorities[i]) < 0.01:
            priorities[i] = 0.01
    return priorities
